INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 1, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 0, 122601, 1, 0.029, 1, 1.5, 160, 1, 101, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 111, 2, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 1, 122401, 0, 0.014, 3, 2.5, 120, 2, 102, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 3, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 0, 122501, 0, 0.017, 2, 2.5, 350, 3, 103, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 4, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 1, 107501, 0, 0.016, 3, 1.5, 130, 4, 104, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 5, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 0, 107601, 1, 0.014, 1, 2.5, 160, 5, 105, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (120, 103, 6, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 0, 107801, 0, 0.029, 2, 3.5, 255, 6, 106, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (120, 103, 7, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 0, 110601, 1, 0.013, 1, 3.5, 160, 7, 107, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 103, 8, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 0, 110401, 0, 0.014, 2, 2.5, 350, 8, 108, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 100, 9, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 1, 110501, 0, 0.012, 3, 1.5, 130, 9, 109, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 103, 10, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 0, 115701, 1, 0.014, 1, 2.5, 200, 10, 110, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 103, 11, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 0, 113601, 0, 0.071, 2, 2.5, 350, 11, 111, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (120, 103, 12, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 1, 107901, 0, 0.014, 3, 1.5, 130, 12, 112, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 13, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 0, 108001, 1, 0.022, 2, 1.5, 200, 13, 113, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 108, 14, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 0, 110301, 1, 0.031, 1, 2.5, 160, 14, 114, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 15, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 1, 107701, 0, 0.036, 1, 0.5, 130, 15, 115, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 95, 16, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 0, 113101, 0, 0.048, 2, 3.5, 350, 16, 116, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 105, 17, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 1, 113301, 0, 0.043, 3, 1.5, 130, 17, 117, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 95, 18, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 1, 113201, 0, 0.018, 2, 1.5, 130, 18, 118, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 108, 19, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 0, 117001, 1, 0.021, 2, 2.5, 160, 19, 119, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 20, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 0, 113501, 0, 0.036, 1, 2.5, 255, 20, 120, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 105, 21, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 0, 113401, 0, 0.02, 3, 2.5, 350, 21, 121, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 22, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 1, 110101, 0, 0.018, 1, 2.5, 130, 22, 122, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 111, 23, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 0, 110001, 1, 0.03, 3, 3.5, 160, 23, 123, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 103, 24, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 1, 117201, 0, 0.027, 1, 1.5, 130, 24, 124, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 108, 25, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 0, 117301, 1, 0.02, 2, 3.5, 160, 25, 125, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 26, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 0, 117401, 0, 0.04, 3, 2.5, 350, 26, 126, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 27, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 0, 117101, 0, 0.009, 1, 3.5, 350, 27, 127, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (120, 105, 28, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 0, 122901, 0, 0.022, 1, 3.5, 255, 28, 128, 1);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (110, 105, 29, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 1, 122801, 0, 0.028, 3, 2.5, 130, 29, 129, 0);
INSERT INTO `v1_98ae641c01c26336f3f46d39047238bee0e2281109429e2b54b8e88737b849da` VALUES (105, 108, 30, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 0, 122701, 1, 0.023, 2, 3.5, 130, 30, 130, 0);
